cards.solution_code:
def iter_config_lines(text):
    out = []
    for line in text.splitlines():
        line = line.strip()
        if not line or line.startswith('#'):
            continue
        out.append(line)
    return out

cards.tests:
import pytest
from solution import iter_config_lines

def test_drops_blank_and_comment_lines():
    text = '# header comment\nname = alice\n\n  # indented comment\nport = 8080\n'
    assert iter_config_lines(text) == ['name = alice', 'port = 8080']

def test_strips_whitespace():
    assert iter_config_lines('   hello   \n\tworld\t') == ['hello', 'world']

def test_preserves_order():
    text = 'a\nb\nc\n'
    assert iter_config_lines(text) == ['a', 'b', 'c']

def test_empty_input():
    assert iter_config_lines('') == []

def test_only_comments_and_blanks():
    assert iter_config_lines('# a\n\n  #b\n') == []

